def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = (1 - ratio) ** 4 + 0.15
        elif 0.7 < ratio <= 0.9:
            score = np.log1p(1 / (ratio * 10 + 0.1)) + 0.05
        elif 0.4 < ratio <= 0.7:
            score = np.sin(ratio * np.pi) * 0.3 + 0.1
        else:
            partial_sum = 0
            for k in range(1, 8):
                term = ((-1) ** k) * (ratio ** (k + 2)) / (k * 2.0)
                partial_sum += term
                if abs(term) < 1e-4:
                    break
            score = abs(partial_sum) + 0.07
        neighbors_influence = 0.0
        neighbor_count = 0
        for offset in range(1, 7):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.2)
                    neighbors_influence += diff_ratio * weight * 0.065
                    neighbor_count += 1
        if neighbor_count > 0:
            neighbors_influence /= neighbor_count
        capacity_factor = np.sqrt(capacity) + 0.5
        priority = score + neighbors_influence / capacity_factor
        if priority < 0:
            priority = 0
        if ratio < 0.3:
            penalty = (0.3 - ratio) * 0.5
            priority += penalty
        elif ratio > 0.95:
            bonus = (ratio - 0.95) * (-1) * 0.4
            priority += bonus
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 4.7
    for i in range(n):
        if bins[i] == item:
            priorities[i] = 0.0
    return priorities
